const TOK = 'CHANGE_ME_TODOIST_TOKEN';
const API = 'https://api.todoist.com/api/v1';
const H = { 'Authorization': 'Bearer ' + TOK, 'Content-Type': 'application/json' };
const PLACEHOLDER = /^(name|notes|due date|when|area|project|tags)$/i;
const b = $json.body || $json;
let tasks = (b && b.tasks !== undefined) ? b.tasks : b;
if (typeof tasks === 'string') {
  const s = tasks.trim();
  try { tasks = JSON.parse(s); }
  catch(e) { tasks = s.split(/\r?\n/).map(l=>l.trim()).filter(Boolean).map(l=>{try{return JSON.parse(l);}catch(_){return null;}}).filter(Boolean); }
}
if (!Array.isArray(tasks)) tasks = [];
let have = new Set();
try { const ex = await this.helpers.httpRequest({ method:'GET', url: API+'/tasks', headers:H, json:true });
      for (const t of (ex.results||ex||[])) if (t&&t.content) have.add(String(t.content).trim().toLowerCase()); } catch(e){}
let created=0, skipped=0, errors=0, date_dropped=0;
const clean = (v)=>{ v=String(v||'').trim(); return (!v||PLACEHOLDER.test(v))?'':v; };
for (const t of tasks) {
  if (t==null || typeof t!=='object') continue;
  if (t.completed===true || String(t.completed)==='true') continue;
  const content = clean(t.title || t.content);
  if (!content) continue;
  const key = content.toLowerCase();
  if (have.has(key)) { skipped++; continue; }
  const body = { content: content.slice(0,400) };
  const notes = clean(t.notes); if (notes) body.description = notes.slice(0,9000);
  const due = clean(t.due);
  if (due) { const m=due.match(/\d{4}-\d{2}-\d{2}/); if (m) body.due_string=m[0]; else if (/\d/.test(due)) body.due_string=due; }
  const proj = clean(t.project || t.area);
  if (proj) { const raw=proj.replace(/[^A-Za-z0-9]+/g,'_').replace(/^_+|_+$/g,''); if (raw) body.labels=['Things_'+raw]; }
  try { await this.helpers.httpRequest({ method:'POST', url:API+'/tasks', headers:H, body, json:true }); created++; have.add(key); }
  catch(e) {
    if (body.due_string) { delete body.due_string; date_dropped++;
      try { await this.helpers.httpRequest({ method:'POST', url:API+'/tasks', headers:H, body, json:true }); created++; have.add(key); }
      catch(e2){ errors++; } }
    else errors++;
  }
}
return [{ json: { ok:true, received: tasks.length, created, skipped, errors, date_dropped } }];
